import { execFileSync } from "node:child_process";
import { readFileSync } from "node:fs";
import os from "node:os";
import path from "node:path";
import { UserError } from "../errors.ts";
import type { AgentConfig } from "../types.ts";

export function resolveHome(): string {
  if (process.platform === "win32") {
    return os.homedir();
  }

  const sudoUser = process.env["SUDO_USER"];
  if (sudoUser) {
    return lookupHomeForUser(sudoUser);
  }

  return os.homedir();
}

function lookupHomeForUser(username: string): string {
  // Method 1: getent passwd (Linux/POSIX — handles LDAP, NIS, local via NSS)
  if (process.platform !== "darwin") {
    try {
      const out = execFileSync("getent", ["passwd", username], {
        encoding: "utf8",
        stdio: ["ignore", "pipe", "ignore"],
      }).trim();
      const home = out.split(":")[5];
      if (typeof home === "string" && home.startsWith("/")) return home;
    } catch {
      // getent unavailable or user not found — try next method
    }
  }

  // Method 2: dscl (macOS directory services)
  if (process.platform === "darwin") {
    try {
      const out = execFileSync(
        "dscl",
        [".", "-read", `/Users/${username}`, "NFSHomeDirectory"],
        { encoding: "utf8", stdio: ["ignore", "pipe", "ignore"] }
      ).trim();
      const home = out.replace(/^NFSHomeDirectory:\s*/, "").trim();
      if (home.startsWith("/")) return home;
    } catch {
      // dscl unavailable or user record not found — try next method
    }
  }

  // Method 3: parse /etc/passwd directly (universal POSIX fallback)
  try {
    const passwd = readFileSync("/etc/passwd", "utf8");
    for (const line of passwd.split("\n")) {
      const parts = line.split(":");
      if (parts[0] === username) {
        const home = parts[5];
        if (typeof home === "string" && home.startsWith("/")) return home;
      }
    }
  } catch {
    // /etc/passwd unavailable — fall through to error
  }

  throw new UserError(
    "RESOLVE_FAILED",
    `Cannot determine home directory for user "${username}". ` +
      `Tried getent, dscl, and /etc/passwd. ` +
      `Run without sudo, or set HOME to the correct path before invoking with sudo.`
  );
}

export function getPlatformKey(): "posix" | "windows" {
  return process.platform === "win32" ? "windows" : "posix";
}

export function getDeployMethod(): "symlink" | "copy" {
  return process.platform === "win32" ? "copy" : "symlink";
}

export function resolveAgentSkillPath(
  agent: AgentConfig,
  skillName: string,
  home: string
): string {
  const platform = getPlatformKey();
  const template = agent.skills[platform];
  return resolvePlaceholders(template, skillName, home);
}

export function resolveAgentDetectPath(
  agent: AgentConfig,
  home: string
): string {
  const platform = getPlatformKey();
  const template = agent.detectPaths[platform];
  return resolvePlaceholders(template, "", home);
}

function resolvePlaceholders(
  template: string,
  skillName: string,
  home: string
): string {
  let result = template.replace("{home}", home);
  result = result.replace("{name}", skillName);

  if (result.includes("{appdata}")) {
    const appdata = process.env["APPDATA"] ?? path.join(home, "AppData", "Roaming");
    result = result.replace("{appdata}", appdata);
  }

  return result;
}

import { describe, it, mock } from "node:test";
import assert from "node:assert/strict";
import os from "node:os";
import { resolveHome, resolveAgentSkillPath, resolveAgentDetectPath } from "../src/core/resolve.ts";
import { AGENT_REGISTRY } from "../src/config/agents.ts";
import { UserError } from "../src/errors.ts";

describe("resolveAgentSkillPath", () => {
  it("resolves Claude Code skill path", () => {
    const claude = AGENT_REGISTRY.find((a) => a.id === "claude-code")!;
    const result = resolveAgentSkillPath(claude, "my-skill", "/Users/test");

    if (process.platform === "win32") {
      assert.equal(result, "/Users/test\\.claude\\skills\\my-skill");
    } else {
      assert.equal(result, "/Users/test/.claude/skills/my-skill");
    }
  });

  it("resolves OpenCode skill path with home", () => {
    const opencode = AGENT_REGISTRY.find((a) => a.id === "opencode")!;
    const result = resolveAgentSkillPath(opencode, "test-skill", "/home/user");

    if (process.platform === "win32") {
      // Uses {appdata} on Windows
      assert.ok(result.includes("opencode"));
    } else {
      assert.equal(result, "/home/user/.config/opencode/skills/test-skill");
    }
  });

  it("resolves Antigravity nested path", () => {
    const antigravity = AGENT_REGISTRY.find((a) => a.id === "antigravity")!;
    const result = resolveAgentSkillPath(antigravity, "my-skill", "/home/user");

    if (process.platform !== "win32") {
      assert.equal(result, "/home/user/.gemini/antigravity/skills/my-skill");
    }
  });
});

describe("resolveAgentDetectPath", () => {
  it("resolves detect path for each agent", () => {
    for (const agent of AGENT_REGISTRY) {
      const result = resolveAgentDetectPath(agent, "/home/user");
      assert.ok(result.startsWith("/home/user") || result.includes("opencode"));
      assert.ok(!result.includes("{home}"));
      assert.ok(!result.includes("{name}"));
    }
  });
});

describe("resolveHome", () => {
  it("returns os.homedir() when SUDO_USER is not set", () => {
    const saved = process.env["SUDO_USER"];
    try {
      delete process.env["SUDO_USER"];
      assert.equal(resolveHome(), os.homedir());
    } finally {
      if (saved === undefined) {
        delete process.env["SUDO_USER"];
      } else {
        process.env["SUDO_USER"] = saved;
      }
    }
  });

  it("looks up real home when SUDO_USER matches the current user", () => {
    if (process.platform === "win32") return;
    const currentUser = process.env["USER"] ?? os.userInfo().username;
    if (!currentUser) return;

    const saved = process.env["SUDO_USER"];
    try {
      process.env["SUDO_USER"] = currentUser;
      const result = resolveHome();
      assert.ok(typeof result === "string" && result.startsWith("/"), `expected absolute path, got: ${result}`);
    } finally {
      if (saved === undefined) {
        delete process.env["SUDO_USER"];
      } else {
        process.env["SUDO_USER"] = saved;
      }
    }
  });

  it("throws UserError when SUDO_USER is a non-existent user", () => {
    if (process.platform === "win32") return;
    const saved = process.env["SUDO_USER"];
    try {
      process.env["SUDO_USER"] = "__nonexistent_user_inception_engine_test__";
      assert.throws(() => resolveHome(), (err: unknown) => {
        assert.ok(err instanceof UserError);
        assert.equal(err.code, "RESOLVE_FAILED");
        assert.match(err.message, /Cannot determine home directory/);
        return true;
      });
    } finally {
      if (saved === undefined) {
        delete process.env["SUDO_USER"];
      } else {
        process.env["SUDO_USER"] = saved;
      }
    }
  });
});

