     1→import { access, lstat, mkdir, symlink, cp, unlink, rm, writeFile } from "node:fs/promises";
     2→import type { Stats } from "node:fs";
     3→import path from "node:path";
     4→import { AGENT_REGISTRY_BY_ID } from "../config/agents.ts";
     5→import { resolveAgentSkillPath, getDeployMethod } from "./resolve.ts";
     6→import { UserError } from "../errors.ts";
     7→import type { AgentId, DeployAction, Manifest } from "../types.ts";
     8→import { logger } from "../logger.ts";
     9→
    10→export function planDeploy(
    11→  manifest: Manifest,
    12→  sourceDir: string,
    13→  detectedAgents: AgentId[],
    14→  home: string
    15→): DeployAction[] {
    16→  const method = getDeployMethod();
    17→  const actions: DeployAction[] = [];
    18→  const resolvedSourceDir = path.resolve(sourceDir);
    19→
    20→  for (const skill of manifest.skills) {
    21→    const source = path.resolve(sourceDir, skill.path);
    22→
    23→    if (source !== resolvedSourceDir && !source.startsWith(resolvedSourceDir + path.sep)) {
    24→      throw new UserError(
    25→        "DEPLOY_FAILED",
    26→        `Skill path "${skill.path}" resolves outside the repository root: ${source}`
    27→      );
    28→    }
    29→
    30→    for (const agentId of skill.agents) {
    31→      if (!detectedAgents.includes(agentId)) continue;
    32→
    33→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    34→      if (!agent) continue;
    35→
    36→      const target = resolveAgentSkillPath(agent, skill.name, home);
    37→
    38→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    39→    }
    40→  }
    41→
    42→  return actions;
    43→}
    44→
    45→export async function executeDeploy(
    46→  actions: DeployAction[],
    47→  dryRun: boolean,
    48→  verbose: boolean
    49→): Promise<{ succeeded: number; failed: Array<{ action: DeployAction; error: string }> }> {
    50→  let succeeded = 0;
    51→  const failed: Array<{ action: DeployAction; error: string }> = [];
    52→
    53→  for (const action of actions) {
    54→    const label = `${action.skill} -> ${action.agent}`;
    55→
    56→    try {
    57→      await access(action.source);
    58→    } catch {
    59→      const msg = `Source not found: ${action.source}`;
    60→      failed.push({ action, error: msg });
    61→      logger.fail(label, msg);
    62→      continue;
    63→    }
    64→
    65→    if (dryRun) {
    66→      logger.plan(label);
    67→      if (verbose) {
    68→        logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
    69→      }
    70→      succeeded++;
    71→      continue;
    72→    }
    73→
    74→    try {
    75→      await removeExisting(action.target, verbose);
    76→      await mkdir(path.dirname(action.target), { recursive: true });
    77→
    78→      if (action.method === "symlink") {
    79→        await symlink(action.source, action.target, "dir");
    80→      } else {
    81→        await cp(action.source, action.target, { recursive: true });
    82→        await writeFile(path.join(action.target, ".inception-totem"), "inception-engine\n");
    83→      }
    84→
    85→      logger.ok(label);
    86→      if (verbose) {
    87→        logger.detail(`${action.method}: ${action.source} -> ${action.target}`);
    88→      }
    89→      succeeded++;
    90→    } catch (err) {
    91→      const msg = err instanceof Error ? err.message : String(err);
    92→      failed.push({ action, error: msg });
    93→      logger.fail(label, msg);
    94→    }
    95→  }
    96→
    97→  return { succeeded, failed };
    98→}
    99→
   100→async function removeExisting(targetPath: string, verbose: boolean): Promise<void> {
   101→  let stat: Stats;
   102→  try {
   103→    stat = await lstat(targetPath);
   104→  } catch {
   105→    return;
   106→  }
   107→
   108→  if (stat.isSymbolicLink()) {
   109→    if (verbose) {
   110→      logger.detail(`removing existing symlink: ${targetPath}`);
   111→    }
   112→    await unlink(targetPath);
   113→  } else {
   114→    if (verbose) {
   115→      logger.warn(targetPath, "replacing existing directory");
   116→    }
   117→    await rm(targetPath, { recursive: true });
   118→  }
   119→}
