     8→export function planRevert(
     9→  manifest: Manifest,
    10→  detectedAgents: AgentId[],
    11→  home: string
    12→): RevertAction[] {
    13→  const actions: RevertAction[] = [];
    14→
    15→  for (const skill of manifest.skills) {
    16→    for (const agentId of skill.agents) {
    17→      if (!detectedAgents.includes(agentId)) continue;
    18→
    19→      const agent = AGENT_REGISTRY_BY_ID[agentId];
    20→      if (!agent) continue;
    21→
    22→      const target = resolveAgentSkillPath(agent, skill.name, home);
    23→      actions.push({ skill: skill.name, agent: agentId, target });
    24→    }
    25→  }
    26→
    27→  return actions;
    28→}
    29→
    30→export async function executeRevert(
    31→  actions: RevertAction[],
    32→  dryRun: boolean,
    33→  verbose: boolean
    34→): Promise<{ succeeded: number; skipped: number }> {
    35→  let succeeded = 0;
    36→  let skipped = 0;
    37→
    38→  for (const action of actions) {
    39→    const label = `${action.skill} -> ${action.agent}`;
    40→
    41→    let stat: Awaited<ReturnType<typeof lstat>>;
    42→    try {
    43→      stat = await lstat(action.target);
    44→    } catch {
    45→      logger.skip(label, "(not found, skipping)");
    46→      skipped++;
    47→      continue;
    48→    }
    49→
    50→    if (!(await isOwnedByInceptionEngine(action.target, stat))) {
    51→      logger.warn(label, `skipping: ${action.target} does not have inception-engine ownership proof — not managed by inception-engine`);
    52→      skipped++;
    53→      continue;
    54→    }
    55→
    56→    if (dryRun) {
    57→      logger.plan(label);
    58→      if (verbose) {
    59→        logger.detail(`would remove: ${action.target}`);
    60→      }
    61→      succeeded++;
    62→      continue;
    63→    }
    64→
    65→    try {
    66→      if (stat.isSymbolicLink()) {
    67→        await unlink(action.target);
    68→      } else {
    69→        await rm(action.target, { recursive: true });
    70→      }
    71→      logger.ok(label);
    72→      if (verbose) {
    73→        logger.detail(`removed: ${action.target}`);
    74→      }
    75→      succeeded++;
    76→    } catch (err) {
    77→      const msg = err instanceof Error ? err.message : String(err);
    78→      logger.fail(label, msg);
    79→    }
    80→  }
    81→
    82→  return { succeeded, skipped };
    83→}
    84→
    85→async function isOwnedByInceptionEngine(
    86→  targetPath: string,
    87→  stat: Awaited<ReturnType<typeof lstat>>
    88→): Promise<boolean> {
    89→  if (stat.isSymbolicLink()) {
    90→    try {
    91→      const linkTarget = await readlink(targetPath);
    92→      const resolved = path.resolve(path.dirname(targetPath), linkTarget);
    93→      await access(path.join(resolved, "SKILL.md"));
    94→      return true;
    95→    } catch {
    96→      return false;
    97→    }
    98→  } else {
    99→    try {
   100→      await access(path.join(targetPath, ".inception-totem"));
   101→      return true;
   102→    } catch {
   103→      return false;
   104→    }
   105→  }
   106→}
